={{
(() => {

  const d = $json.DISTRIBUICAO;

  if (!d || !d.atual || !d.anterior || !d.comparativo) {
    return '';
  }

  const n = (v) => Number(v ?? 0);

  const num = (v, casas = 0) =>
    n(v).toLocaleString('pt-BR', {
      minimumFractionDigits: casas,
      maximumFractionDigits: casas
    });

  const pct = (v, casas = 1) =>
    n(v).toLocaleString('pt-BR', {
      minimumFractionDigits: casas,
      maximumFractionDigits: casas
    });

  const icone = (obj) => obj?.icone ?? '➖';

  return `*DISTRIBUIÇÃO*

Período: ${d.atual.inicio ?? '-'} a ${d.atual.fim ?? '-'} (${$('GET DIAS').item.json.dias} dias) | Comparativo com ${d.anterior.inicio ?? '-'} a ${d.anterior.fim ?? '-'}

Gargalo: 🦆 | Está bom: 🦅
• Alcance: ${num(d.atual.alcance)} | ${icone(d.comparativo.alcance)}${pct(d.comparativo.alcance?.variacao)}%
• Cliques: ${num(d.atual.cliques)} | ${icone(d.comparativo.cliques)}${pct(d.comparativo.cliques?.variacao)}%
• CTR: ${num(d.atual.ctr, 2)}% | ${icone(d.comparativo.ctr)}${pct(d.comparativo.ctr?.variacao_pp, 2)} pp (${n(d.atual.ctr)>2?'🦅':'🦆'})
• CPC: R$ ${num(d.atual.cpc, 2)} | ${icone(d.comparativo.cpc)}${pct(d.comparativo.cpc?.variacao)}% (${n(d.atual.cpc)<0.5?'🦅':'🦆'})
• Engajamentos: ${num(d.atual.post_engagement)} | ${icone(d.comparativo.post_engagement)}${pct(d.comparativo.post_engagement?.variacao)}%
• Investimento: R$ ${num(d.atual.investimento, 2)} | ${icone(d.comparativo.investimento)}${pct(d.comparativo.investimento?.variacao)}%`;

})()
}}

