  // Se não existir em um dos períodos, ignora
  if (!atual || !anterior) {
    return null;
  }

  const resultado = {
    atual,
    anterior,
    comparativo: {

      investimento: {
        variacao: variacao(atual.investimento, anterior.investimento),
