const items = $input.all().map(i => i.json);

// Organiza por período e campanha
const dados = {};

for (const item of items) {
  if (!dados[item.periodo]) dados[item.periodo] = {};
  dados[item.periodo][item.campanha] = item;
}

function variacao(atual, anterior) {
  atual = Number(atual);
  anterior = Number(anterior);

  if (!isFinite(atual) || !isFinite(anterior) || anterior === 0) {
    return null;
  }

  return ((atual - anterior) / anterior) * 100;
}

function direcao(atual, anterior, menorMelhor = false, tolerancia = 0) {
  atual = Number(atual);
  anterior = Number(anterior);

  const dif = atual - anterior;

  if (Math.abs(dif) <= tolerancia) {
    return "➖";
  }

  if (menorMelhor) {
    return dif < 0 ? "🟢" : "🔴";
  }

  return dif > 0 ? "🟢" : "🔴";
}

function compararCampanha(nomeCampanha) {

  const atual = dados.atual[nomeCampanha];
  const anterior = dados.anterior[nomeCampanha];

  const resultado = {
    atual,
    anterior,
    comparativo: {

      investimento: {
        variacao: variacao(atual.investimento, anterior.investimento),
        icone: direcao(
          variacao(atual.investimento, anterior.investimento),
          0,
          false,
          10
        )
      },

      impressoes: {
        variacao: variacao(atual.impressoes, anterior.impressoes),
        icone: direcao(atual.impressoes, anterior.impressoes)
      },

      alcance: {
        variacao: variacao(atual.alcance, anterior.alcance),
        icone: direcao(atual.alcance, anterior.alcance)
      },

      cliques: {
        variacao: variacao(atual.cliques, anterior.cliques),
        icone: direcao(atual.cliques, anterior.cliques)
      },

      ctr: {
        variacao_pp: Number(atual.ctr) - Number(anterior.ctr),
        icone: direcao(atual.ctr, anterior.ctr, false, 0.20)
      },

      cpc: {
        variacao: variacao(atual.cpc, anterior.cpc),
        icone: direcao(
          variacao(atual.cpc, anterior.cpc),
          0,
          true,
          5
        )
      },

      landing_page_view: {
        variacao: variacao(
          atual.landing_page_view,
          anterior.landing_page_view
        ),
        icone: direcao(
          atual.landing_page_view,
          anterior.landing_page_view
        )
      },

      post_engagement: {
        variacao: variacao(
          atual.post_engagement,
          anterior.post_engagement
        ),
        icone: direcao(
          atual.post_engagement,
          anterior.post_engagement
        )
      }

    }
  };

  // Apenas CAPTURA possui métricas de funil
  if (nomeCampanha === "CAPTURA") {

    resultado.comparativo.contatos = {
      variacao: variacao(atual.contatos, anterior.contatos),
      icone: direcao(atual.contatos, anterior.contatos)
    };

    resultado.comparativo.conversao_funil = {
      variacao_pp:
        Number(atual.conversao_funil_pct) -
        Number(anterior.conversao_funil_pct),

      icone: direcao(
        atual.conversao_funil_pct,
        anterior.conversao_funil_pct,
        false,
        2
      )
    };

    resultado.comparativo.custo_por_contato = {
      variacao: variacao(
        atual.custo_por_contato,
        anterior.custo_por_contato
      ),

      icone: direcao(
        variacao(
          atual.custo_por_contato,
          anterior.custo_por_contato
        ),
        0,
        true,
        5
      )
    };

  }

  return resultado;
}

return [
  {
    json: {
      CAPTURA: compararCampanha("CAPTURA"),
      DISTRIBUICAO: compararCampanha("DISTRIBUICAO")
    }
  }
];

