const periodo = $('start end 5').item.json;
const dias = Number(periodo.dias);

function subtrairDias(data, qtdDias) {
  const d = new Date(data);
  d.setDate(d.getDate() - qtdDias);

  return d.toISOString().slice(0, 10);
}

const [atualResp, anteriorResp, mesResp] = $input.all().map(i => i.json);

const atual = atualResp.results;
const anterior = anteriorResp.results;

const investimentoMes = Number(mesResp.cost || 0);

function variacao(atual, anterior) {
	atual = Number(atual);
	anterior = Number(anterior);

	if (!isFinite(atual) || !isFinite(anterior) || anterior === 0) {
		return null;
	}

	return ((atual - anterior) / anterior) * 100;
}

function direcao(atual, anterior, menorMelhor = false, tolerancia = 0) {

	atual = Number(atual);
	anterior = Number(anterior);

	if (!isFinite(atual) || !isFinite(anterior)) {
		return "➖";
	}

	const dif = atual - anterior;

	if (Math.abs(dif) <= tolerancia) {
		return "➖";
	}

	if (menorMelhor) {
		return dif < 0 ? "🟢" : "🔴";
	}

	return dif > 0 ? "🟢" : "🔴";
}

const campanhasAnteriores = {};

for (const campanha of anterior) {
	campanhasAnteriores[campanha.campaign.id] = campanha;
}

const resultado = {};

const totalAtual = {
	investimento: 0,
	impressoes: 0,
	cliques: 0,
	conversoes: 0,
	todas_conversoes: 0,
	valor_conversoes: 0,
	valor_todas_conversoes: 0
};

const totalAnterior = {
	investimento: 0,
	impressoes: 0,
	cliques: 0,
	conversoes: 0,
	todas_conversoes: 0,
	valor_conversoes: 0,
	valor_todas_conversoes: 0
};

for (const campanhaAtual of atual) {

	const campanhaAnterior = campanhasAnteriores[campanhaAtual.campaign.id];

	if (!campanhaAnterior) continue;

	const a = campanhaAtual.metrics;
	const b = campanhaAnterior.metrics;

    totalAtual.investimento += Number(a.costMicros) / 1e6;
    totalAtual.impressoes += Number(a.impressions);
    totalAtual.cliques += Number(a.clicks);
    totalAtual.conversoes += Number(a.conversions);
    totalAtual.todas_conversoes += Number(a.allConversions);
    totalAtual.valor_conversoes += Number(a.conversionsValue);
    totalAtual.valor_todas_conversoes += Number(a.allConversionsValue);

    totalAnterior.investimento += Number(b.costMicros) / 1e6;
    totalAnterior.impressoes += Number(b.impressions);
    totalAnterior.cliques += Number(b.clicks);
    totalAnterior.conversoes += Number(b.conversions);
    totalAnterior.todas_conversoes += Number(b.allConversions);
    totalAnterior.valor_conversoes += Number(b.conversionsValue);
    totalAnterior.valor_todas_conversoes += Number(b.allConversionsValue);

	const nome = campanhaAtual.campaign.name;

	resultado[nome] = {

		atual: {
            inicio: periodo.start_date,
