			cpm: Number(a.averageCpm) / 1e6,
			ctr: Number(a.ctr) * 100,
			cliques: Number(a.clicks),
			cpc: Number(a.averageCpc) / 1e6,
			conversoes: Number(a.conversions),
			todas_conversoes: Number(a.allConversions),
			valor_conversoes: Number(a.conversionsValue),
			valor_todas_conversoes: Number(a.allConversionsValue)
		},

		anterior: {
            inicio: subtrairDias(periodo.start_date, dias),
